#pragma once
#include <cuda_runtime.h>
#include <cuda_bf16.h>

// Kernel launch configuration
#define BLOCK_SIZE 256
#define HEAD_SIZE 128
#define NUM_V_HEADS 16
#define NUM_Q_HEADS 8
#define NUM_K_HEADS 8
#define SEQ_LEN 1

/**
 * GDN Decode Kernel
 * 
 * Computes the recurrent state update and output for Gated Delta Net decode.
 * Optimized for A800 with 128x128 state matrix in shared memory.
 * 
 * @param output Output tensor [B, 1, H, V] (BF16)
 * @param new_state New state tensor [B, H, V, K] (F32)
 * @param q Query tensor [B, 1, Q, K] (BF16)
 * @param k Key tensor [B, 1, K, K] (BF16)
 * @param v Value tensor [B, 1, V, V] (BF16)
 * @param state Input state tensor [B, H, V, K] (F32)
 * @param A_log Log decay parameter [H] (F32)
 * @param a Input-dependent decay [B, 1, H] (BF16)
 * @param dt_bias Decay bias [H] (F32)
 * @param b Update gate input [B, 1, H] (BF16)
 * @param scale Scale factor (F32)
 * @param batch_size Number of sequences
 */
__global__ void gdn_decode_kernel(
    __nv_bfloat16* output,
    float* new_state,
    const __nv_bfloat16* q,
    const __nv_bfloat16* k,
    const __nv_bfloat16* v,
    const float* state,
    const float* A_log,
    const __nv_bfloat16* a,
    const float* dt_bias,
    const __nv_bfloat16* b,
    float scale,
    int batch_size
);

/**
 * Host function wrapper
 */
void launch_gdn_decode(
    __nv_bfloat16* output,
    float* new_state,
    const __nv_bfloat16* q,
    const __nv_bfloat16* k,
    const __nv_bfloat16* v,
    const float* state,
    const float* A_log,
    const __nv_bfloat16* a,
    const float* dt_bias,
    const __nv_bfloat16* b,
    float scale,
    int batch_size
);

#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <math.h>
#include "kernel.h"

__global__ void gdn_decode_kernel(
    __nv_bfloat16* output,
    float* new_state,
    const __nv_bfloat16* q,
    const __nv_bfloat16* k,
    const __nv_bfloat16* v,
    const float* state,
    const float* A_log,
    const __nv_bfloat16* a,
    const float* dt_bias,
    const __nv_bfloat16* b,
    float scale,
    int batch_size
) {
    // Grid configuration: 1 block per (batch, v_head) pair
    int head_idx = blockIdx.x % NUM_V_HEADS;
    int batch_idx = blockIdx.x / NUM_V_HEADS;

    if (batch_idx >= batch_size) return;

    // Map V head to Q/K heads (GVA mode: 2 V heads per Q/K head)
    int q_head_idx = head_idx / 2;
    int k_head_idx = head_idx / 2;

    // Shared memory for state [V, K] = [128, 128]
    // 64KB, fits in A800 SM (240KB)
    __shared__ float s_state[HEAD_SIZE][HEAD_SIZE];
    __shared__ float s_old_v[HEAD_SIZE];
    __shared__ float s_q_state_v[HEAD_SIZE]; // q @ state_row_v
    __shared__ float s_diff_v[HEAD_SIZE];
    __shared__ float s_dot_qk;
    __shared__ float s_g;
    __shared__ float s_beta;

    // Registers for q, k, v (loaded as bf162, converted to float)
    __nv_bfloat162 s_q_vec[64]; // 128 elements
    __nv_bfloat162 s_k_vec[64];
    __nv_bfloat162 s_v_vec[64];

    int tid = threadIdx.x;
    int lane = tid % 32;
    int warp_id = tid / 32;

    // Load q, k, v
    // q, k: [B, 1, 8, 128]
    // v: [B, 1, 16, 128]
    // Stride for q/k: 8 * 128
    // Stride for v: 16 * 128

    int q_base = batch_idx * NUM_Q_HEADS * HEAD_SIZE + q_head_idx * HEAD_SIZE;
    int k_base = batch_idx * NUM_K_HEADS * HEAD_SIZE + k_head_idx * HEAD_SIZE;
    int v_base = batch_idx * NUM_V_HEADS * HEAD_SIZE + head_idx * HEAD_SIZE;

    // Load q, k, v into registers
    for (int i = tid; i < HEAD_SIZE; i += BLOCK_SIZE) {
        __nv_bfloat162 q_val = reinterpret_cast<const __nv_bfloat162*>(q)[q_base + i/2];
        __nv_bfloat162 k_val = reinterpret_cast<const __nv_bfloat162*>(k)[k_base + i/2];
        __nv_bfloat162 v_val = reinterpret_cast<const __nv_bfloat162*>(v)[v_base + i/2];

        s_q_vec[i/2] = q_val;
        s_k_vec[i/2] = k_val;
        s_v_vec[i/2] = v_val;
    }
    __syncthreads();

    // Load state [B, H, V, K]
    // Stride: H * V * K = 16 * 128 * 128
    int state_base = batch_idx * NUM_V_HEADS * HEAD_SIZE * HEAD_SIZE + head_idx * HEAD_SIZE * HEAD_SIZE;

    // Load state into shared memory
    for (int i = tid; i < HEAD_SIZE * HEAD_SIZE; i += BLOCK_SIZE) {
        int v = i / HEAD_SIZE;
        int k = i % HEAD_SIZE;
        s_state[v][k] = state[state_base + v * HEAD_SIZE + k];
    }
    __syncthreads();

    // Compute g and beta
    // a: [B, 1, 16], b: [B, 1, 16]
    // A_log: [16], dt_bias: [16]
    int a_base = batch_idx * NUM_V_HEADS + head_idx;
    int b_base = batch_idx * NUM_V_HEADS + head_idx;

    float a_val = __bfloat162float(reinterpret_cast<const __nv_bfloat162*>(a)[a_base/2]);
    float b_val = __bfloat162float(reinterpret_cast<const __nv_bfloat162*>(b)[b_base/2]);
    float A_log_val = A_log[head_idx];
    float dt_bias_val = dt_bias[head_idx];

    float x = a_val + dt_bias_val;
    float softplus_x = logf(1.0f + expf(x));
    float g_val = expf(-expf(A_log_val) * softplus_x);
    float beta_val = 1.0f / (1.0f + expf(-b_val));

    if (tid == 0) {
        s_g = g_val;
        s_beta = beta_val;
    }
    __syncthreads();

    float g = s_g;
    float beta = s_beta;

    // Compute old_v[v] = sum_k (k[k] * state[v][k])
    // Compute q_state_v[v] = sum_k (q[k] * state[v][k])
    // Compute dot_qk = sum_k (q[k] * k[k])

    // We use 128 threads for this phase (tid 0-127)
    if (tid < HEAD_SIZE) {
        float old_v_acc = 0.0f;
        float q_state_v_acc = 0.0f;
        float dot_qk_acc = 0.0f;

        for (int k = 0; k < HEAD_SIZE; ++k) {
            // Convert bf16 to float
            float k_f = __bfloat162float(s_k_vec[k/2]);
            float q_f = __bfloat162float(s_q_vec[k/2]);
            // Handle even/odd
            if (k % 2 == 1) {
                k_f = __bfloat162float(s_k_vec[k/2]);
                q_f = __bfloat162float(s_q_vec[k/2]);
            }

            // Correct vector access
            // s_k_vec[k/2] contains 2 values.
            // If k is even, take low. If k is odd, take high.
            // __bfloat162float returns float2.
            float2 k2 = __bfloat162float2(s_k_vec[k/2]);
            float2 q2 = __bfloat162float2(s_q_vec[k/2]);

            float k_val_k = (k % 2 == 0) ? k2.x : k2.y;
            float q_val_k = (k % 2 == 0) ? q2.x : q2.y;

            float s_val = s_state[tid][k];

            old_v_acc += k_val_k * s_val;
            q_state_v_acc += q_val_k * s_val;
            dot_qk_acc += q_val_k * k_val_k;
        }

        s_old_v[tid] = old_v_acc;
        s_q_state_v[tid] = q_state_v_acc;
        if (tid == 0) s_dot_qk = dot_qk_acc;
    }
    __syncthreads();

    // Compute diff_v[v] = beta * (v[v] - old_v[v])
    if (tid < HEAD_SIZE) {
        float2 v2 = __bfloat162float2(s_v_vec[tid/2]);
        float v_val = (tid % 2 == 0) ? v2.x : v2.y;
        float diff = beta * (v_val - s_old_v[tid]);
        s_diff_v[tid] = diff;
    }
    __syncthreads();

    // Update state and compute output
    // new_state[v][k] = g * state[v][k] + k[k] * diff_v[v]
    // output[v] = g * q_state_v[v] + diff_v[v] * dot_qk

    float dot_qk = s_dot_qk;

    // Each thread handles a subset of the matrix
    // 256 threads, 16384 elements -> 64 elements per thread
    for (int i = tid; i < HEAD_SIZE * HEAD_SIZE; i += BLOCK_SIZE) {
        int v = i / HEAD_SIZE;
        int k = i % HEAD_SIZE;

        float s_val = s_state[v][k];
        float k_val = __bfloat162float(s_k_vec[k/2]);
        if (k % 2 == 1) k_val = __bfloat162float(s_k_vec[k/2]); // Fix: use float2

        float2 k2 = __bfloat162float2(s_k_vec[k/2]);
        float k_f = (k % 2 == 0) ? k2.x : k2.y;

        float diff_v = s_diff_v[v];

        float new_s_val = g * s_val + k_f * diff_v;
        s_state[v][k] = new_s_val;
    }
    __syncthreads();

    // Write back state
    int state_out_base = batch_idx * NUM_V_HEADS * HEAD_SIZE * HEAD_SIZE + head_idx * HEAD_SIZE * HEAD_SIZE;
    for (int i = tid; i < HEAD_SIZE * HEAD_SIZE; i += BLOCK_SIZE) {
        int v = i / HEAD_SIZE;
        int k = i % HEAD_SIZE;
        new_state[state_out_base + v * HEAD_SIZE + k] = s_state[v][k];
    }
    __syncthreads();

    // Compute and write output
    // output: [B, 1, H, V]
    // output[b, 0, h, v]
    int out_base = batch_idx * NUM_V_HEADS * HEAD_SIZE + head_idx * HEAD_SIZE;

    if (tid < HEAD_SIZE) {
        float q_state_v = s_q_state_v[tid];
        float diff_v = s_diff_v[tid];
        float out_val = scale * (g * q_state_v + diff_v * dot_qk);

        __nv_bfloat16 out_bf16 = __float2bfloat16(out_val);
        output[out_base + tid] = out_bf16;
    }
}

void launch_gdn_decode(
    __nv_bfloat16* output,
    float* new_state,
    const __nv_bfloat16* q,
    const __nv_bfloat16* k,
    const __nv_bfloat16* v,
    const float* state,
    const float* A_log,
    const __nv_bfloat16* a,
    const float* dt_bias,
    const __nv_bfloat16* b,
    float scale,
    int batch_size
) {
    int grid_size = batch_size * NUM_V_HEADS;
    gdn_decode_kernel<<<grid_size, BLOCK_SIZE>>>(
        output, new_state, q, k, v, state, A_log, a, dt_bias, b, scale, batch_size
    );
}

#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <math.h>
#include "kernel.h"

// Helper to check CUDA errors
#define CUDA_CHECK(call) \
    do { \
        cudaError_t err = call; \
        if (err != cudaSuccess) { \
            throw std::runtime_error(std::string("CUDA error: ") + cudaGetErrorString(err)); \
        } \
    } while (0)

std::vector<torch::Tensor> run(
    torch::Tensor q,
    torch::Tensor k,
    torch::Tensor v,
    torch::Tensor state,
    torch::Tensor A_log,
    torch::Tensor a,
    torch::Tensor dt_bias,
    torch::Tensor b,
    torch::Tensor scale
) {
    // Validate inputs
    TORCH_CHECK(q.is_cuda(), "q must be on CUDA");
    TORCH_CHECK(k.is_cuda(), "k must be on CUDA");
    TORCH_CHECK(v.is_cuda(), "v must be on CUDA");
    TORCH_CHECK(state.is_cuda(), "state must be on CUDA");
    TORCH_CHECK(A_log.is_cuda(), "A_log must be on CUDA");
    TORCH_CHECK(a.is_cuda(), "a must be on CUDA");
    TORCH_CHECK(dt_bias.is_cuda(), "dt_bias must be on CUDA");
    TORCH_CHECK(b.is_cuda(), "b must be on CUDA");

    TORCH_CHECK(q.dtype() == torch::kBFloat16, "q must be bfloat16");
    TORCH_CHECK(k.dtype() == torch::kBFloat16, "k must be bfloat16");
    TORCH_CHECK(v.dtype() == torch::kBFloat16, "v must be bfloat16");
    TORCH_CHECK(state.dtype() == torch::kFloat32, "state must be float32");
    TORCH_CHECK(A_log.dtype() == torch::kFloat32, "A_log must be float32");
    TORCH_CHECK(a.dtype() == torch::kBFloat16, "a must be bfloat16");
    TORCH_CHECK(dt_bias.dtype() == torch::kFloat32, "dt_bias must be float32");
    TORCH_CHECK(b.dtype() == torch::kBFloat16, "b must be bfloat16");

    int batch_size = q.size(0);
    int seq_len = q.size(1);
    int num_q_heads = q.size(2);
    int head_size = q.size(3);

    TORCH_CHECK(seq_len == 1, "seq_len must be 1");
    TORCH_CHECK(num_q_heads == 8, "num_q_heads must be 8");
    TORCH_CHECK(head_size == 128, "head_size must be 128");
    TORCH_CHECK(k.size(2) == 8, "num_k_heads must be 8");
    TORCH_CHECK(v.size(2) == 16, "num_v_heads must be 16");
    TORCH_CHECK(state.size(1) == 16, "state num_v_heads must be 16");
    TORCH_CHECK(state.size(2) == 128, "state V must be 128");
    TORCH_CHECK(state.size(3) == 128, "state K must be 128");

    // Handle scale
    float scale_val = 1.0f / std::sqrt(static_cast<float>(head_size));
    if (scale.numel() > 0) {
        scale_val = scale.item<float>();
        if (scale_val == 0.0f) {
            scale_val = 1.0f / std::sqrt(static_cast<float>(head_size));
        }
    }

    // Allocate output tensors
    auto output = torch::empty({batch_size, 1, 16, 128}, torch::TensorOptions().dtype(torch::kBFloat16).device(torch::kCUDA));
    auto new_state = torch::empty({batch_size, 16, 128, 128}, torch::TensorOptions().dtype(torch::kFloat32).device(torch::kCUDA));

    // Get raw pointers
    __nv_bfloat16* q_ptr = reinterpret_cast<__nv_bfloat16*>(q.data_ptr<__nv_bfloat16>());
    __nv_bfloat16* k_ptr = reinterpret_cast<__nv_bfloat16*>(k.data_ptr<__nv_bfloat16>());
    __nv_bfloat16* v_ptr = reinterpret_cast<__nv_bfloat16*>(v.data_ptr<__nv_bfloat16>());
    float* state_ptr = state.data_ptr<float>();
    float* A_log_ptr = A_log.data_ptr<float>();
    __nv_bfloat16* a_ptr = reinterpret_cast<__nv_bfloat16*>(a.data_ptr<__nv_bfloat16>());
    float* dt_bias_ptr = dt_bias.data_ptr<float>();
    __nv_bfloat16* b_ptr = reinterpret_cast<__nv_bfloat16*>(b.data_ptr<__nv_bfloat16>());

    __nv_bfloat16* output_ptr = reinterpret_cast<__nv_bfloat16*>(output.data_ptr<__nv_bfloat16>());
    float* new_state_ptr = new_state.data_ptr<float>();

    // Launch kernel
    launch_gdn_decode(
        output_ptr,
        new_state_ptr,
        q_ptr,
        k_ptr,
        v_ptr,
        state_ptr,
        A_log_ptr,
        a_ptr,
        dt_bias_ptr,
        b_ptr,
        scale_val,
        batch_size
    );

    CUDA_CHECK(cudaGetLastError());
    CUDA_CHECK(cudaDeviceSynchronize());

    return {output, new_state};
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run, "GDN Decode Kernel");
}
